+        boolean hasAnyVars = false;
+        for (JCTree.JCBindingPattern bp : patternBindings) {
+            Tree bindingTypeTree = bp.getVariable().getType();
+            if (bindingTypeTree.getKind() == Tree.Kind.VAR_TYPE) {
+                hasAnyVars = true;
+            }
+        }
